/***************************************************************
 * 文件名: ds3231.h
 * 说    明: DS3231 RTC 实时时钟模块 — 数据结构和 API 声明
 *           I2C1 总线 (PB7=SCL, PB6=SDA), 地址 0x68, 100kHz
 *           RTC_Time 结构体提供线程安全读写接口
 ***************************************************************/

#ifndef _DS3231_H_
#define _DS3231_H_

#include <stdint.h>

/***************************************************************
 * 数据结构: RTC_Time
 * 说    明: 完整的日期时间结构体
 *           year:   年份 (如 2026), 完整四位数
 *           month:  月份 (1~12)
 *           day:    日期 (1~31)
 *           hour:   小时 (0~23)
 *           minute: 分钟 (0~59)
 *           second: 秒 (0~59)
 ***************************************************************/
typedef struct {
    uint16_t year;
    uint8_t month;
    uint8_t day;
    uint8_t hour;
    uint8_t minute;
    uint8_t second;
} RTC_Time;

/* 全局时间变量, 由 rtc_task 线程定期更新, 供 UI 和其他模块读取 */
extern volatile RTC_Time g_rtc_time;

/***************************************************************
 * 函数名称: ds3231_init
 * 说    明: 初始化 I2C1 总线和 DS3231 芯片
 *           首次上电时通过标志位检测并写入默认时间
 ***************************************************************/
void ds3231_init(void);

/***************************************************************
 * 函数名称: ds3231_set_datetime
 * 说    明: 设置 DS3231 芯片的日期时间 (逐寄存器安全写入)
 * 参    数:
 *       @year:   年份, 如 2026
 *       @month:  月份 (1~12)
 *       @day:    日期 (1~31)
 *       @h:      小时 (0~23)
 *       @m:      分钟 (0~59)
 *       @s:      秒 (0~59)
 * 返 回 值: 0=成功, 非0=写入失败
 ***************************************************************/
int ds3231_set_datetime(uint16_t year, uint8_t month, uint8_t day, uint8_t h, uint8_t m, uint8_t s);

/***************************************************************
 * 函数名称: ds3231_get_datetime
 * 说    明: 从 DS3231 芯片一次性读取 7 个时间寄存器
 * 参    数:
 *       @time: [输出] 接收读取到的日期时间
 ***************************************************************/
void ds3231_get_datetime(RTC_Time *time);

/***************************************************************
 * 函数名称: rtc_time_read_safe
 * 说    明: 线程安全地读取全局时间变量 (带互斥锁 g_rtc_mutex 保护)
 *           供外部模块 (UI/voice/cloud) 获取最新时间
 * 参    数:
 *       @out: [输出] 接收拷贝出的时间值
 ***************************************************************/
void rtc_time_read_safe(RTC_Time *out);

#endif /* _DS3231_H_ */
